import{_ as a,o,c as t,ae as i}from"./chunks/framework.CyZiF_rV.js";const n="/ksef-docs/assets/hwm.CnKORmUR.png",r="/ksef-docs/assets/hwm-1.Bdx9PjiU.png",s="/ksef-docs/assets/hwm-2.CZj0KUSn.png",m=JSON.parse('{"title":"High Water Mark (HWM)","description":"","frontmatter":{},"headers":[],"relativePath":"pl/pobieranie-faktur/hwm.md","filePath":"pl/pobieranie-faktur/hwm.md"}'),c={name:"pl/pobieranie-faktur/hwm.md"};function d(z,e,l,p,u,y){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="high-water-mark-hwm" tabindex="-1">High Water Mark (HWM) <a class="header-anchor" href="#high-water-mark-hwm" aria-label="Permalink to &quot;High Water Mark (HWM)&quot;">​</a></h1><p>25.11.2025</p><p>Mechanizm High Water Mark (HWM) opisuje, jak KSeF zarządza kompletnością danych w czasie dla daty <code>PermanentStorage</code>.</p><p>W każdej chwili system zna moment w czasie (<code>HWM</code>), do którego ma już pewność, że wszystkie faktury zostały zapisane i nie pojawią się nowe dokumenty z datą <code>PermanentStorage</code> wcześniejszą lub równą temu momentowi.</p><p><img src="'+n+'" alt="HWM"></p><ul><li>Dla czasu ≤ <code>HWM</code> - wszystkie faktury z datą <code>PermanentStorage</code> w tym przedziale zostały już trwale zapisane w KSeF. System gwarantuje, że w przyszłości nie pojawi się już żadna nowa faktura z datą <code>PermanentStorage</code> ≤ <code>HWM</code>.</li><li>W przedziale (<code>HWM</code>, <code>Teraz</code>): <ul><li>część faktur jest już widoczna i może zostać zwrócona w zapytaniu,</li><li>z uwagi na asynchroniczny i wielowątkowy charakter procesu zapisu, w tym przedziale mogą się jeszcze pojawić nowe faktury, tj. z datą <code>PermanentStorage</code> mieszczącą się w zakresie (<code>HWM</code>, <code>Teraz</code>].</li></ul></li></ul><p>Wniosek:</p><ul><li>wszystko, co ≤ <code>HWM</code>, można traktować jako zbiór <strong>zamknięty</strong> i <strong>kompletny</strong>,</li><li>wszystko, co &gt; <code>HWM</code>, jest <strong>potencjalnie niepełne</strong> i wymaga ostrożnego traktowania przy synchronizacji.</li></ul><h2 id="scenariusz-1-synchronizacja-tylko-do-hwm" tabindex="-1">Scenariusz 1 - synchronizacja &quot;tylko do HWM&quot; <a class="header-anchor" href="#scenariusz-1-synchronizacja-tylko-do-hwm" aria-label="Permalink to &quot;Scenariusz 1 - synchronizacja &quot;tylko do HWM&quot;&quot;">​</a></h2><p><img src="'+r+'" alt="HWM-1"></p><p>System przy każdym zapytaniu pobiera faktury <strong>od &quot;ostatniego znanego punktu&quot; tylko do bieżącej wartości <code>HWM</code></strong>. Nowa wartość <code>HWM</code> staje się początkiem kolejnego przedziału.</p><p>Zalety:</p><ul><li>dane do <code>HWM</code> są definitywne - nie trzeba ponownie sprawdzać tego samego przedziału,</li><li>liczba duplikatów między kolejnymi pobraniami jest minimalna.</li></ul><p>Konsekwencje:</p><ul><li>część najświeższych faktur z zakresu <code>(HWM, Teraz]</code> nie jest widoczna w systemie lokalnym - pojawią się dopiero po przesunięciu <code>HWM</code> w kolejnym cyklu.</li></ul><p>Scenariusz ten jest rekomendowany dla przyrostowego, automatycznego synchronizowania danych, w których ważniejsza od natychmiastowej dostępności najświeższych faktur jest optymalizacja ruchu i minimalizacja liczby duplikatów.</p><h2 id="scenariusz-2-synchronizacja-do-teraz" tabindex="-1">Scenariusz 2 - synchronizacja &quot;do Teraz&quot; <a class="header-anchor" href="#scenariusz-2-synchronizacja-do-teraz" aria-label="Permalink to &quot;Scenariusz 2 - synchronizacja &quot;do Teraz&quot;&quot;">​</a></h2><p><img src="'+s+'" alt="HWM-2"></p><p>System integrujący się z KSeF wykonuje cykliczne, przyrostowe zapytania <strong>od ostatniego punktu startowego aż do <code>Teraz</code></strong> i zapisuje wszystkie zwrócone faktury, również z przedziału <code>(HWM, Teraz]</code>.</p><p>Ponieważ dane w tym przedziale mogą być niepełne, <strong>kolejne zapytanie powtarza część zakresu</strong> - co najmniej od poprzedniego <code>HWM</code> do nowego <code>Teraz</code>. Po stronie systemu lokalnego konieczna jest deduplikacja (np. po numerze KSeF).</p><p>Zalety:</p><ul><li>lokalny system (i użytkownik) widzi najnowsze faktury możliwie szybko, bez czekania aż <code>HWM</code> je &quot;dogoni&quot;.</li></ul><p>Konsekwencje:</p><ul><li>zakres <code>(HWM, Teraz]</code> musi być sprawdzany ponownie przy kolejnym zapytaniu,</li><li>pojawią się duplikaty, które należy usuwać po stronie systemu lokalnego.</li></ul><p>Ten sam mechanizm może być wykorzystywany również <strong>ad hoc</strong>, gdy użytkownik ręcznie żąda odświeżenia danych - system pobiera wtedy &quot;tu i teraz&quot; najświeższe dostępne faktury od ostatnio znanej daty aż do <code>Teraz</code>.</p><h2 id="powiazane-dokumenty" tabindex="-1">Powiązane dokumenty <a class="header-anchor" href="#powiazane-dokumenty" aria-label="Permalink to &quot;Powiązane dokumenty&quot;">​</a></h2><ul><li><a href="./przyrostowe-pobieranie-faktur.html">Przyrostowe pobieranie faktur</a></li></ul>',27)])])}const k=a(c,[["render",d]]);export{m as __pageData,k as default};
